from fastapi import FastAPI, Header, HTTPException, Depends
from datetime import datetime, timezone
import redis, os, json, hashlib

r = redis.Redis.from_url(os.environ.get("REDIS_URL", "redis://localhost:6379"), decode_responses=True)

def _cache_key(key_hash: str) -> str:
    return f"apikey:{key_hash}"

def verify_api_key(x_api_key: str = Header(...)) -> APIKey:
    key_hash = hashlib.sha256(x_api_key.encode()).hexdigest()

    # Check cache first
    cached = r.get(_cache_key(key_hash))
    if cached:
        data = json.loads(cached)
        record = APIKey(
            id=data["id"],
            key_hash=key_hash,
            tenant_id=data["tenant_id"],
            scopes=data["scopes"],
            expires_at=datetime.fromisoformat(data["expires_at"]) if data.get("expires_at") else None,
            revoked=data["revoked"],
        )
    else:
        record = lookup_key(x_api_key)   # from _KEY_STORE or real DB
        if record:
            r.setex(
                _cache_key(key_hash), 30,   # 30-second TTL
                json.dumps({
                    "id": record.id,
                    "tenant_id": record.tenant_id,
                    "scopes": record.scopes,
                    "expires_at": record.expires_at.isoformat() if record.expires_at else None,
                    "revoked": record.revoked,
                }),
            )

    if record is None:
        raise HTTPException(status_code=401, detail="Invalid API key")
    if record.revoked:
        raise HTTPException(status_code=401, detail="API key has been revoked")
    if record.expires_at and record.expires_at < datetime.now(timezone.utc):
        raise HTTPException(status_code=401, detail="API key has expired")
    return record

app = FastAPI()

@app.post("/agent/run")
async def run_agent_endpoint(body: dict, key: APIKey = Depends(verify_api_key)):
    if "write" not in key.scopes and body.get("action") == "write":
        raise HTTPException(status_code=403, detail="This key does not have write scope")
    return {"tenant": key.tenant_id, "result": "..."}

SCOPE_TO_TOOLS = {
    "read":  ["search_documents", "get_record", "list_files"],
    "write": ["create_record", "update_record", "upload_file"],
    "admin": ["delete_record", "bulk_export", "manage_users"],
}

def get_tools_for_key(key: APIKey) -> list[str]:
    allowed = set()
    for scope in key.scopes:
        allowed.update(SCOPE_TO_TOOLS.get(scope, []))
    return list(allowed)

def can_use_tool(tool_name: str, key: APIKey) -> bool:
    return tool_name in get_tools_for_key(key)

# Usage in agent tool dispatch:
def execute_tool(name: str, inputs: dict, key: APIKey) -> str:
    import json
    if not can_use_tool(name, key):
        return json.dumps({"error": "scope_denied", "tool": name, "key_scopes": key.scopes})
    # ... actual tool execution
    return json.dumps({"result": "ok"})
